var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"......이 정도면 주변에 얼씬거리는 것들은 다 치운 것 같군.","JPN":"……これくらいなら、周りにうろついてるのは全部片付いたようだ。","ENG":"That should have taken care of most of the C.O.s around here.","TWN":"……這樣的話，殺來附近的東西差不多都除掉了。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"VISITOR_NPC_SUMMER_NULL","text":{"KOREA":"가, 감사합니다!","JPN":"あ、ありがとうございます！","ENG":"Th-thank you!","TWN":"非、非常謝謝妳！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"VISITOR_NPC_SUMMER_NULL","text":{"KOREA":"근처에 카운터가 계셔서 다행이에요!","JPN":"近くにカウンターがいてよかったです！","ENG":"Thank God, we've got a Counter in the midst of us!","TWN":"有制裁者在附近真是太好了！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"괜찮아. 이제 안전해. 당신도 그만 가보라고.","JPN":"大丈夫、もう安全だ。お前も帰っていいぞ。","ENG":"You're welcome. Everything's okay now. You can go.","TWN":"放心，現在安全了，你也快走吧。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VISITOR_NPC_SUMMER_NULL","text":{"KOREA":"그래서야 은인에 대한 예의가 아니죠. 답례로 저녁만찬은 어떠신가요?","JPN":"このまま帰ったら恩人に対して失礼です。お礼にディナーはいかがですか？","ENG":"But I'd like to repay you. How about I treat you to dinner tonight?","TWN":"這樣不是對待恩人該有的禮儀，作為謝禮，我請妳吃頓晚餐如何？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"괘, 괜찮은데.","JPN":"べ、別にいらない。","ENG":"Th-that wouldn't be necessary.","TWN":"不、不用了。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"VISITOR_NPC_SUMMER_NULL","text":{"KOREA":"혹시 혼자 오셨나요? 오늘 선상파티가 있을 예정인데 같이 동행하시죠!","JPN":"もしかして、一人で来られたのですか？\\n今日、船上パーティーが行われる予定ですが、一緒にどうですか？","ENG":"Are you here alone? There will be a cruise party tonight. How'd you like to come with me?","TWN":"妳是一個人來的嗎？今天我們預定要舉辦船上派對，妳也一起參加吧！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"응? 그거 VIP만 참석할 수 있는 행사 아닌가? 난 그런 거 없는데......","JPN":"うん？　それはVIPしか参加できないパーティーじゃないのか？　私はVIPじゃないのだが……","ENG":"Huh? I thought that was for VIPs only. I'm not a VIP.","TWN":"咦？那個不是只有VIP才能參加的活動嗎？我不是VIP啊……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"난 우리 동사무소 단체 워크숍 사전 답사로 온 거라......","JPN":"私は役所のワークショップの下見で来ただけで……","ENG":"I came here location-scouting for the city hall's next workshop...","TWN":"我是為了我們區公所旅遊團先來這裡踩點的……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"VISITOR_NPC_SUMMER_NULL","text":{"KOREA":"괜찮습니다, VIP들은 파트너를 데려갈 수 있거든요. 당신이 함께 있어준다면 파티가 훨씬 빛날 겁니다!","JPN":"大丈夫です。VIPはパートナーを連れていくことができますから。\\nあなたが一緒にいてくれれば、パーティーがもっと輝くはずです！","ENG":"Don't worry. VIPs can bring partners with them. Please come with me and grace the party with your presence!","TWN":"沒關係，VIP可以帶同伴一起參加。如果妳能夠參加，一定可以讓派對更添光彩的！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"그, 그래도 갑자기 그런 걸 권하면 곤란하달까......","JPN":"だ、だが急に誘われて困るというか……","ENG":"B-but this is all too sudden...","TWN":"不、不過這有點太突然了，我有點困擾……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"와아, 저 언니. 엄청난 실력의 카운터였네요.","JPN":"わぁ、あのお姉さん。すごい腕前のカウンターだったんですね。","ENG":"Wow, that lady. She is an incredible Counter!","TWN":"哇，那個姐姐原來是一個超強的制裁者呢。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"후훗, 이러면 저흰 나설 필요도 없었겠는데요?","JPN":"ふふっ、私たちが出るまでもなかったんですね。","ENG":"Hah hah. We didn't even have to step in.","TWN":"呵呵，這樣就不需要我們出手了吧？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"저, 저 사람 방금 뭐였죠? 검을 휘두르는 것도 안 보였는데, 침식체들이 순식간에......","JPN":"あ、あの人は何なんですか？　剣を振るうところが見えなかったんですが、あっという間に侵食体が……","ENG":"W-what did she do? I didn't even see her swinging her sword, and the C.O.s instantly dropped like fallen leaves.","TWN":"那個人剛才做了什麼？也沒看到她揮刀，侵蝕體瞬間就倒地了……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"흐음~ 인기가 많은 여자라더니, 저 녀석이 네가 말한 다음 운명의 고리인가 보군.","JPN":"ふう～ん、モテる女だそうだが、あいつが其方の言ってた次の運命の相手みたいじゃ。","ENG":"Hm, a popular woman, huh? She must be the next link of your destiny.","TWN":"嗯～確實是個受歡迎的女性，看來她就是妳說的下一個命運之環了。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"특히 저 눈...... 제법 흥미로운데?","JPN":"特にあの目……なかなか面白いのう。","ENG":"And that eye... It's pretty interesting.","TWN":"尤其是那隻眼睛……好像很有趣嘛？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"헤헤, 표범가죽! 너 엄청 강하구나?","JPN":"へへ、ヒョウ革！　あんた、強いよな？","ENG":"Heh heh, leopard skin! You're pretty strong!","TWN":"嘿嘿，豹紋！妳很強嘛？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"뭐지? 이 들개 같은 녀석은.","JPN":"何だ、この野良犬みたいな奴は。","ENG":"Who is this wild dog?","TWN":"這個像野狗的傢伙又是誰？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"나랑 한판 붙어보는 건 어때? 재밌을 것 같은데.","JPN":"アタシと勝負しよう。面白そうだ。","ENG":"How'd you like to have a match with me? I think it's going to be fun.","TWN":"妳要不要跟我打一架？我想這一定很好玩。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"그 원숭이랑 같은 부류인가 보군.","JPN":"あの猿と同じ類のようだな。","ENG":"You're the same type as the monkey.","TWN":"看來跟那隻猴子是同一類傢伙。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"모처럼 나온 휴가다. 싸움질엔 관심 없으니 다른데 가서 알아보라고.","JPN":"せっかくの休暇だ。喧嘩には興味ないから、他を当たれ。","ENG":"I don't get to take vacations often. I don't want to waste my time on fighting. Go find someone else.","TWN":"現在是我難得的假期，我可沒興趣打架，妳去找別人吧。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"쳇, 시시한 녀석이네. 싸움만큼 재미있는 게 대체 어디에 있다고.","JPN":"ちっ、つまらない奴だな。喧嘩ほど面白いものはないのよ。","ENG":"Bah, you're boring. Nothing's more fun than fighting.","TWN":"切，真無趣的傢伙。哪有比打架更有趣的事情啊。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"하하, 저희 어프로치가 좀 터프했죠?","JPN":"ハハ、私たちのアプローチが少し過激だったようですね？","ENG":"Hah hah. I'm sorry if we came on too strong.","TWN":"哈哈，是我們太唐突了吧？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"사실은 언니에게 좀 물어보고 싶은 게 있었거든요.","JPN":"実は、お姉さんにお聞きしたいことがあるんです。","ENG":"We just want to ask you a question.","TWN":"其實我們有事情想要問問姐姐。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"물어볼 것?","JPN":"聞きたいこと？","ENG":"A question?","TWN":"問我？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"네. 저희 일행 중의 한 명이 언니 같은 인기인이 되고 싶어 하거든요!","JPN":"はい、私の連れの一人がお姉さんのような人気者になりたがってるんです。","ENG":"Yes. One of us wants to know how to become as popular as you.","TWN":"是的。我們當中有一個人想變得像姐姐一樣受歡迎！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그러니까 어떻게 해야 이성에게 인기를 얻을 수 있는지 좀 가르쳐주실 수 없을까요?","JPN":"だから、異性にモテる方法を教えていただけませんか？","ENG":"Could you tell us your secrets to attracting the opposite sex?","TWN":"妳能不能告訴我們怎樣才能吸引異性？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"이, 인기인......? 내가?","JPN":"に、人気者……？　私が？","ENG":"P-popular? Me?","TWN":"名、名人……？我？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그럼요! 잘 생긴 남자들이 계속 언니에게 같이 놀자고 조르잖아요?","JPN":"はい！　イケメンたちが次々とお姉さんに一緒に遊ぼうって誘ってるじゃないですか？","ENG":"Yes! Handsome men keep asking you to spend time with them.","TWN":"是啊！不是有很多帥哥纏著妳，邀妳跟他們一起玩嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"그, 그게 놀자는 의도였어? 자꾸 번호를 달래서 난 그냥 전도사 같은 건 줄 알았는데......","JPN":"そ、そういうことだったのか？　番号を教えてほしいというから、てっきり詐欺師のようなもんだと思ったのだが……","ENG":"D-did they want to spend time with me? They kept asking me for my phone number. I thought they were just trying to sell me something.","TWN":"那是想和我玩的意思？他們老是問我的電話號碼，我還以為是傳教士呢……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"흠, 딱히 의도하신 건 아닌 모양이네요? 그럼 역시 비결은 분위기인가?","JPN":"ふーん、特に色目を使ったりしなかったみたいですね。じゃあ、やっぱり秘訣は雰囲気かな？","ENG":"Hm, so you weren't drawing them on purpose. Then, maybe your secret is your mystique.","TWN":"嗯，看來妳不是有意要吸引異性的？難道秘訣是氣質嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"의뢰인 언니도 저런 수영복을 입어보는 건 어때요?","JPN":"依頼人のお姉さんも、あんな感じの水着を着てみたらどうですか？","ENG":"Client lady, how about you try wearing a bathing suit like hers?","TWN":"委託人姐姐要不要也來試試這種泳裝？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"저어...... 의상 문제를 떠나서 제 몸은 원본과 굴곡의 차이가 너무 다른데요.","JPN":"あの……水着の問題じゃなくて、私とあの方では体のボリューム感が違いすぎるというか。","ENG":"Erm, I don't think I have the body for it.","TWN":"那個……我想不是泳裝的問題。我的身體曲線和她差太多了。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"......미안하지만, 딱히 비결 같은 건 없어. 연애문제라면 다른 사람을 알아보는 편이 좋을 거야.","JPN":"……悪いが、特にコツとかはない。色恋沙汰なら他の人に聞いたほうがいい。","ENG":"I'm sorry, but I don't have any secrets. If you need help with relationship problems, you should ask someone else.","TWN":"……抱歉，我真的沒有什麼秘訣。戀愛問題還是去問別人吧。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"굳이 그런 수고는 할 필요 없다. 여기선 내가 도와주지.","JPN":"わざわざそんな手間をかけてなくてよい。ここからは妾が手伝ってやろう。","ENG":"No need to look elsewhere. I'm here.","TWN":"不用費那麼大的功夫，在這裡我就可以幫你們。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"당신은......?","JPN":"お前は……？","ENG":"You?","TWN":"妳是……？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"줄곧 지켜봤는데, 인간 주제에 꽤 재미있는 눈을 가지고 있더군.","JPN":"ずっと見ておったが、人間のくせになかなか面白い目を持っておるようじゃのう。","ENG":"I've been watching you. You've got a pretty interesting eye for a human.","TWN":"我一直在旁邊觀察妳，沒想到區區一個人類竟然擁有這麼有趣的眼睛。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"당신...... 정체가 뭐지?","JPN":"お前……何者だ？","ENG":"You... Who the hell are you?","TWN":"妳……是什麼人？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"자세한 건 알 것 없어. 오늘 하루는 나를 <color=#83dcb7>사랑의 마왕님</color>이라고 소개해 두지.","JPN":"詳しく知らなくてよい。今日一日は、妾を<color=#83dcb7>愛の魔王様</color>とでも紹介しておこう。","ENG":"You don't need to know. For now, I'm the <color=#83dcb7>Demon Lord of Love</color>.","TWN":"妳不需要知道。今天妳就姑且叫我<color=#83dcb7>愛情魔王</color>吧。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"그 보다 네 눈의 힘을 좀 써야겠어.","JPN":"それより、其方の目の力を借りよう。","ENG":"By the way, I need to borrow your eye.","TWN":"比起這些事情，我想稍微借用妳眼睛的力量。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"내 권능을 조금만 부여해주면 그 눈으로 운명의 상대 또한 볼 수 있게 될 거다.","JPN":"妾の権能を少し与えてやれば、その目で運命の相手を見つけられるようになるはずじゃ。","ENG":"With a little bit of my power, your eye should be able to recognize soul mates.","TWN":"如果我把我的能力稍微賦予給妳，妳就能用那隻眼睛看到命運之人了。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"잠깐, 누구 마음대로 눈에 손을 댄다는 거지?","JPN":"待て、勝手に人の目に手を出すんじゃない。","ENG":"Wait, you can't touch my eye!","TWN":"等等，誰允許妳碰我的眼睛了？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"손을 대? 내가?","JPN":"手を出す？　妾が？","ENG":"Touch your eye? Who? Me?","TWN":"碰妳的眼睛？我嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"아하하하, 이 몸이 그런 하급마법사 같은 짓을 할 것 같으냐?","JPN":"あははは、この妾がそんな下級の魔法使いみたいな真似をすると思うか？","ENG":"Ah Hah hah! Only third-rate mages require physical contact.","TWN":"啊哈哈哈，我怎麼可能會做那種下等法師才做的把戲？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"이렇게 손가락 한 번만 튕기면 되는 것을!","JPN":"こうして指を弾くだけで済むことを！","ENG":"As for me, I can just flick my fingers like this.","TWN":"我只要像這樣彈個手指就行了！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"이, 이건...... 도대체 뭐지? 세상이 온통 분홍빛깔이라니......","JPN":"こ、これは……いったい何だ？　世界が全てピンク色になっている……","ENG":"W-what... What's going on? The world is in pink now.","TWN":"這、這是……怎麼回事？世界竟然都變成了粉紅色……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_82"},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"이제 보이겠지? 인간들 사이를 엮고 있는 운명의 고리들이.","JPN":"これで見えてきただろう？　人間たちの間を結んでいる運命の糸が。","ENG":"Now, you can see the rings of destiny that connect humans, can't you?","TWN":"現在看到了吧？連接人和人之間的命運之環。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"자, 말해보거라! 음침한 처녀의 운명은 지금 어느 곳으로 향해 있지?","JPN":"さあ、言ってみろ！　陰気な乙女の運命は今どこへ向かっておるのじゃ？","ENG":"Then, tell me. Where's this gloomy maiden's soul mate right now?","TWN":"那麼，妳就告訴我吧！陰沉女孩的命運指向什麼地方？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"음침한 처녀? 아, 저 미역머리 여자를 말하는 건가?","JPN":"陰気な乙女？　ああ、あのワカメ頭の女のことか？","ENG":"Gloomy maiden? Oh, that seaweed-haired woman?","TWN":"陰沉女孩？喔，是指那個海帶頭女孩嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"제발 나한테 이상한 호칭 붙이는 것 좀 그만둬줄래요?","JPN":"お願いですから、私に変なあだ名を付けるのをやめてもらえませんか？","ENG":"People, would you please stop calling me those stupid names?","TWN":"能不能不要再給我取奇怪的綽號了？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"내가 보는 이 분홍빛 끈이 당신들이 말하는 운명의 고리인진 모르겠지만......","JPN":"私に見えるこのピンク色の糸が、お前たちが言ってる運命の糸なのかはわからないが……","ENG":"I don't know if these pink strings I'm seeing are the rings of destiny you're talking about,","TWN":"我不知道我看到的粉紅色的線，是不是妳所說的命運之環……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"미역머리의 분홍빛 끈은 저쪽으로 이어져있어.","JPN":"ワカメ頭のピンク色の糸は、あっちに繋がっている。","ENG":"but Seaweed Hair's is leading that way.","TWN":"但海帶頭的粉紅色的線指向了那裡。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"어라? 저쪽에 보이는 거라면......","JPN":"あれ？　あっちに見えるのって……","ENG":"Huh? What lies there is...","TWN":"咦？那邊是……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"하, 학교?","JPN":"が、学校？","ENG":"A-a school?!","TWN":"學、學校？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"이, 이봐요! 난 범죄자가 될 생각은 없거든요?!","JPN":"ちょ、ちょっと！　私は犯罪者になるつもりはありませんよ！","ENG":"E-excuse me, I'm not a child molester!","TWN":"喂，喂！我可不想當罪犯耶？！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"난 내가 보이는 그대로 말해줬을 뿐이야. 판단은 알아서 해.","JPN":"私は、目に見えることをそのまま話しただけだ。判断は任せる。","ENG":"I only told you what I saw. It's your call to believe it or not.","TWN":"我只是說出我眼睛看到的東西而已，妳自己判斷就好。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"그보다 애초에, 당신...... 성인이었어?","JPN":"それより、そもそもお前……成人だったのか？","ENG":"By the way, were you... an adult?","TWN":"不過，話說回來，妳……是成年人嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"뭐, 뭐야! 실례잖아! 방금 뭘 비교하면서 말한 거야?!","JPN":"な、何ですか！　失礼じゃないですか！　何と比べながら言ってるんですか！？","ENG":"W-what? That's rude! What did you compare right now?","TWN":"什、什麼！太失禮了！妳剛才是在比較什麼東西？！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"딱히 아무 것도 안 봤는데?","JPN":"別に何も見てないが？","ENG":"I didn't compare anything.","TWN":"我什麼都沒看啊？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"아하하, 너무 흥분하지 마세요. 어리게 봐줬으니 좋은 게 좋은 거죠.","JPN":"あはは、そんなに興奮しないでください。若く見られたからよかったということで。","ENG":"Ah hah hah. Please don't be so angry. This also means you look young.","TWN":"啊哈哈，別這麼激動嘛。看起來很年輕不是很好嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"크윽......","JPN":"くっ……","ENG":"Hmpf!","TWN":"唔……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"우선 언니 분 말씀대로 저기 가보는 게 어때요? 학교라고 해서 꼭 학생만 있으라는 법은 없잖아요?","JPN":"とりあえず、お姉さんの言う通りにあっちに行ってみませんか？\\n学校だからといって、必ずしも学生だけがいるとは限りませんしね。","ENG":"For now, why don't we go check the place out like she said? Students are not the only occupants of the school.","TWN":"我們就先聽這位姐姐說的，到那裡看看怎麼樣？學校裡又不是只有學生而已啊？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......뭐, 그야 그렇긴 하네요. 제가 너무 성급하게 판단했을지도......","JPN":"……まぁ、それもそうですね。私の判断が早すぎたのかも……","ENG":"Well, true. Maybe I was too impatient to make a judgment.","TWN":"……嗯，妳說得沒錯。是我太快下判斷了……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그, 그만 쳐다보라니까!","JPN":"じ、じろじろ見ないでください！","ENG":"S-stop looking!","TWN":"不、不要再看了啦！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};